module pulse_detect(
    input clk, rst_n, data_in,
    output data_out
);

reg [1:0] data_in_d;
reg data_out_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_in_d <= 2'b00;
        data_out_r <= 1'b0;
    end else begin
        data_in_d <= {data_in_d[0], data_in};
        if (data_in_d == 2'b01)
            data_out_r <= 1'b1;
        else
            data_out_r <= 1'b0;
    end
end

assign data_out = data_out_r;

endmodule
